#include "Helper.h"#include <iostream>#include <fstream>#include <sstream>#include <memory>#include "Book.h"#include "Movie.h"#include "Magazine.h"using namespace std;vector<string> split(const string& line, char delimiter) {    vector<string> parts;    string part;    stringstream ss(line);    while (getline(ss, part, delimiter)) {        parts.push_back(part);    }    return parts;}void loadItemsFromFile(const string& fileName, LibraryInventory& libraryInventory) {    ifstream inputFile(fileName);    if (!inputFile) {        cout << "Error: Could not open file " << fileName << endl;        return;    }    string line;    while (getline(inputFile, line)) {        if (line.empty()) {            continue;        }        vector<string> data = split(line, '|');        string type = data[0];        int shelf = stoi(data[1]);        int compartment = stoi(data[2]);        if (type == "BOOK") {            libraryInventory.addItem(                shelf,                compartment,                make_unique<Book>(                    data[3],                    data[4],                    data[5],                    data[6],                    data[7],                    data[8]                )            );        }        else if (type == "MOVIE") {            vector<string> actors = split(data[8], ',');            libraryInventory.addItem(                shelf,                compartment,                make_unique<Movie>(                    data[3],                    data[4],                    data[5],                    data[6],                    data[7],                    actors                )            );        }        else if (type == "MAGAZINE") {            libraryInventory.addItem(                shelf,                compartment,                make_unique<Magazine>(                    data[3],                    data[4],                    data[5],                    data[6],                    data[7]                )            );        }        else {            cout << "Error: Unknown item type: " << type << endl;        }    }    inputFile.close();}